sys_atf_test_step.step:
(function step(assert, $library) {
    // Test Scorecard Result CRUD operations
    // Create
    var gr = new GlideRecord('u_idp_scorecard_result');
    gr.initialize();
    gr.u_name = 'Test Scorecard Result ATF';
    gr.u_score = 85;
    var id = gr.insert();
    assert.isTrue(id, 'Scorecard result should be created');

    // Read
    gr = new GlideRecord('u_idp_scorecard_result');
    gr.get(id);
    assert.equal(gr.u_name, 'Test Scorecard Result ATF', 'Scorecard result name should match');

    // Update
    gr.u_score = 90;
    gr.update();

    // Delete
    gr.deleteRecord();

    // Verify deletion
    gr = new GlideRecord('u_idp_scorecard_result');
    gr.get(id);
    assert.isFalse(gr.isValid(), 'Scorecard result should be deleted');
})(step, $library);
